mapper.select:
/* TM_ECS_INTN_USR_INFO_Dao_retrieveUsrInqire */ SELECT empno AS usr_id, korname AS usr_nm, empno AS usr_empno, dept AS usr_dept_nm, buscd AS usr_dept_cd, posit AS usr_ofcps_nm, calcd AS usr_ofcps_cd, grade AS usr_jgrd_nm, zgrcd AS usr_jgrd_cd, 'Y' AS use_yn FROM HRM.vm_hr01601 WHERE 1=1
AND buscd = #{usrDeptCd}
AND korname LIKE '%' || #{usrNm} || '%'
ORDER BY dept, empno, korname

/* TM_ECS_INTN_USR_INFO_Dao_retrieveUsr */ SELECT DISTINCT B.empno AS usr_id, B.korname AS usr_nm, B.empno AS usr_empno, B.buscd AS usr_dept_cd, B.dept AS usr_dept_nm, B.calcd AS usr_ofcps_cd, B.posit AS usr_ofcps_nm, B.zgrcd AS usr_jgrd_cd, B.grade AS usr_jgrd_nm FROM tm_ecs_intn_usr_menu A, HRM.vm_hr01601 B WHERE A.usr_id = B.empno
/* 사용자 검색을 하여 조회 시 */ AND A.usr_id = #{usrId}
/* 부서명으로 검색시 */ AND B.buscd = #{usrDeptCd}
ORDER BY B.empno
